CREATE TRIGGER [dbo].[OrderItemUnitConsumption_History]ON [dbo].[OrderItemUnitConsumption]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.OrderItemUnitConsumptionId IS NOT NULL AND d.OrderItemUnitConsumptionId IS NULL THEN 'I' 		WHEN i.OrderItemUnitConsumptionId IS NOT NULL AND d.OrderItemUnitConsumptionId IS NOT NULL THEN 'U' 		WHEN i.OrderItemUnitConsumptionId IS NULL AND d.OrderItemUnitConsumptionId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.OrderItemUnitConsumptionId = d.OrderItemUnitConsumptionId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_OrderItemUnitConsumption([OrderItemUnitConsumptionId], [OrderItemUnitId], [EquipmentId], [UserId], [BillOfProcessProcessWorkElementAttributeId], [ConsumedSerialNumber], [IsConsumed], [ConsumedDate], [ConsumedDateUtc], [RemovedDate], [RemovedDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [OrderItemUnitConsumptionId], [OrderItemUnitId], [EquipmentId], [UserId], [BillOfProcessProcessWorkElementAttributeId], [ConsumedSerialNumber], [IsConsumed], [ConsumedDate], [ConsumedDateUtc], [RemovedDate], [RemovedDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_OrderItemUnitConsumption([OrderItemUnitConsumptionId], [OrderItemUnitId], [EquipmentId], [UserId], [BillOfProcessProcessWorkElementAttributeId], [ConsumedSerialNumber], [IsConsumed], [ConsumedDate], [ConsumedDateUtc], [RemovedDate], [RemovedDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [OrderItemUnitConsumptionId], [OrderItemUnitId], [EquipmentId], [UserId], [BillOfProcessProcessWorkElementAttributeId], [ConsumedSerialNumber], [IsConsumed], [ConsumedDate], [ConsumedDateUtc], [RemovedDate], [RemovedDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND
